export const lightTheme = {
  colors: {
    primary: '#FF00FF', // magenta
    secondary: '#90EE90', // light green
    accent: '#FFFF00', // yellow
    background: '#FFFFFF',
    text: '#000000',
  },
};

export const darkTheme = {
  colors: {
    primary: '#8B008B', // dark magenta
    secondary: '#006400', // dark green
    accent: '#B8860B', // dark yellow
    background: '#000000',
    text: '#FFFFFF',
  },
};
